firmware_template.source:
#include "stepper_tmc2209.h"
#include <TMCStepper.h>
#include <HardwareSerial.h>
#define STEP_P 25
#define DIR_P 26
#define EN_P 27
static HardwareSerial tmcSerial(1);
static TMC2209Stepper driver(&tmcSerial,0.11f,0);
void tmc2209_setup(){tmcSerial.begin(115200,SERIAL_8N1,16,17);driver.begin();driver.toff(4);driver.rms_current(800);driver.microsteps(16);driver.pwm_autoscale(true);pinMode(STEP_P,OUTPUT);pinMode(DIR_P,OUTPUT);pinMode(EN_P,OUTPUT);digitalWrite(EN_P,LOW);Serial.println("[tmc2209] OK");}
void tmc2209_move(int32_t s,bool cw){digitalWrite(DIR_P,cw);for(int32_t i=0;i<abs(s);i++){digitalWrite(STEP_P,HIGH);delayMicroseconds(100);digitalWrite(STEP_P,LOW);delayMicroseconds(100);}}
void tmc2209_set_current(uint16_t mA){driver.rms_current(mA);}
void tmc2209_set_microsteps(uint16_t ms){driver.microsteps(ms);}
void tmc2209_enable(bool e){digitalWrite(EN_P,e?LOW:HIGH);}
